      const lineWidth = this.getTextWidthCached(line)
      const centerX = (this.pageWidth - lineWidth) / 2
      this.doc.text(line, centerX, this.currentY)
      this.currentY += 6
    })

    this.currentY += 15
  }

  private checkPageBreak(neededHeight: number, context: 'title' | 'paragraph' | 'list' | 'section' = 'paragraph'): boolean {
    const availableSpace = this.pageHeight - this.margin.bottom - 15 - this.currentY

    // Se não cabe de forma alguma, quebra a página
    if (neededHeight > availableSpace) {
      this.addPageNumber()
      this.newPage()
      return true
    }

    // Lógica inteligente baseada no contexto
    switch (context) {
      case 'title':
        // Títulos precisam de pelo menos 20mm de espaço após eles para evitar órfãos
        if (availableSpace < neededHeight + 20) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break

      case 'section':
        // Seções precisam de pelo menos 30mm de espaço para não quebrar no início
        if (availableSpace < neededHeight + 30) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break

      case 'list':
        // Listas pequenas (até 3 itens) não devem quebrar
        if (neededHeight <= 25 && availableSpace < neededHeight) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break

      case 'paragraph':
      default:
        // Parágrafos pequenos (até 15mm) não devem quebrar
        if (neededHeight <= 15 && availableSpace < neededHeight) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break
    }

    return false
  }

  private newPage() {
    this.doc.addPage()
    this.pageNumber++
    this.currentY = this.margin.top + 5
    this.addWatermark()
    this.addFooterLogo()
  }

  private addCustomFooter() {
    const footerY = this.pageHeight - 15

    // Logo customizável no rodapé
    if (this.customization.footer?.showLogo) {
      try {
        this.doc.addImage(
          WA_PROJECT_LOGO_BASE64,
          'SVG',
          this.contentStartX,
          footerY - 10,
          20,
          8,
          undefined,
          'FAST'
        )
      } catch (error) {
        // Fallback textual
        this.doc.setTextColor(WA_COLORS.primary)
        this.doc.setFontSize(8)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text('Wa Project', this.contentStartX, footerY)
      }
    }

    // Texto customizado no rodapé (centro)
    if (this.customization.footer?.customText) {
      this.doc.setTextColor(WA_COLORS.textMuted)
      this.doc.setFontSize(8)
      this.doc.setFont('helvetica', 'normal')
      const textWidth = this.getTextWidthCached(this.customization.footer.customText)
      const centerX = (this.pageWidth - textWidth) / 2
      this.doc.text(this.customization.footer.customText, centerX, footerY)
    }

    // Número da página customizável (direita)
    if (this.customization.footer?.showPageNumber) {
      this.doc.setTextColor(WA_COLORS.primary)
      this.doc.setFontSize(10)
      this.doc.setFont('helvetica', 'normal')
      this.doc.text(
        this.pageNumber.toString(),
        this.pageWidth - this.margin.right,
        footerY,
        { align: 'right' }
      )
    }
  }

  // Manter compatibilidade com método original
  private addFooterLogo() {
    this.addCustomFooter()
  }

  private addPageNumber() {
    this.doc.setFontSize(9)
    this.doc.setTextColor(WA_COLORS.textMuted)
    this.doc.text(
      this.pageNumber.toString(),
      this.pageWidth / 2,
      this.pageHeight - 10,
      { align: 'center' }
    )
  }

  private addSectionTitle(title: string) {
    this.checkPageBreak(15, 'title')

    this.doc.setTextColor(WA_COLORS.primary)
    this.doc.setFontSize(16)
    this.doc.setFont('helvetica', 'bold')
    this.doc.text(title, this.contentStartX, this.currentY)
    this.currentY += 12
  }

  private addParagraph(text: string) {
    this.doc.setTextColor(WA_COLORS.text)
    this.doc.setFontSize(11)
    this.doc.setFont('helvetica', 'normal')

    const lines = this.doc.splitTextToSize(text, this.contentWidth)

    // Calcular altura total do parágrafo
    const totalParagraphHeight = lines.length * 6 + 4

    // Verificar se o parágrafo inteiro cabe na página
    this.checkPageBreak(totalParagraphHeight, 'paragraph')

    lines.forEach((line: string) => {
      this.doc.text(line, this.contentStartX, this.currentY)
      this.currentY += 6
    })

    this.currentY += 4
  }

  private addBulletList(items: string[]) {
    // Calcular altura estimada da lista completa
    const estimatedListHeight = items.length * 8
    this.checkPageBreak(estimatedListHeight, 'list')

    // Para listas grandes, usar renderização em lote
    if (items.length > 20) {
      this.batchRenderItems(items, (item, index) => {
        this.renderBulletItem(item)
      })
    } else {
      // Para listas pequenas, renderização direta
      items.forEach(item => {
        this.renderBulletItem(item)
      })
    }
  }

  private renderBulletItem(item: string) {
    // Para itens individuais, usar contexto de parágrafo
    this.checkPageBreak(8, 'paragraph')

    // Bullet point
    this.doc.setTextColor(WA_COLORS.primary)
    this.doc.text('•', this.contentStartX, this.currentY)

    // Texto do item
    this.doc.setTextColor(WA_COLORS.textMuted)
    this.doc.setFontSize(10)
    this.doc.setFont('helvetica', 'normal')

    const lines = this.doc.splitTextToSize(item, this.contentWidth - 8)
    lines.forEach((line: string, lineIndex: number) => {
      if (lineIndex > 0) this.checkPageBreak(5, 'paragraph')
      this.doc.text(line, this.contentStartX + 6, this.currentY)
      if (lineIndex < lines.length - 1) this.currentY += 5
    })

    this.currentY += 6
  }

  private parseMarkdownContent(content: string): void {
    const lines = content.split('\n')

    for (const line of lines) {
      const trimmed = line.trim()

      if (!trimmed) {
        this.currentY += 3
        continue
      }

      // Títulos
      if (trimmed.startsWith('### ') || trimmed.startsWith('## ') || trimmed.startsWith('# ')) {
        const titleText = trimmed.replace(/^#+\s+/, '')

        // Verificar quebra de página para títulos
        this.checkPageBreak(8, 'title')

        this.doc.setTextColor(WA_COLORS.primary)
        this.doc.setFontSize(12)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text(titleText, this.contentStartX, this.currentY)
        this.currentY += 8
        continue
      }

      // Listas com bullets
      if (trimmed.startsWith('• ') || trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
        const itemText = trimmed.slice(2).replace(/\*\*(.*?)\*\*/g, '$1')
        this.addBulletList([itemText])
        continue
      }

      // Listas numeradas
      const numberedMatch = trimmed.match(/^(\d+)\.\s+(.+)$/)
      if (numberedMatch) {
        const itemText = numberedMatch[2].replace(/\*\*(.*?)\*\*/g, '$1')

        this.checkPageBreak(8, 'paragraph')
        this.doc.setTextColor(WA_COLORS.primary)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text(`${numberedMatch[1]}.`, this.contentStartX, this.currentY)

        this.doc.setTextColor(WA_COLORS.textMuted)
        this.doc.setFont('helvetica', 'normal')
        this.doc.text(itemText, this.contentStartX + 8, this.currentY)
        this.currentY += 6
        continue
      }

      // Parágrafos regulares
      if (trimmed && !trimmed.startsWith('-') && !trimmed.startsWith('|')) {
        const plainText = trimmed.replace(/\*\*(.*?)\*\*/g, '$1')
        this.addParagraph(plainText)
      }
    }
  }

  public generate(data: WaProjectProposalData, progressCallback?: (progress: number) => void): void {
    // Estimar altura total para otimização
    this.estimatedHeight = this.estimateTotalHeight(data)

    // Adicionar marca d'água na primeira página
    this.addWatermark()
    progressCallback?.(5)

    // PÁGINA 1: CAPA
    this.addHeader(data)
    this.addTitle('Proposta Comercial', data.projeto.nome)
    this.addCoverInfo(data)
    progressCallback?.(15)

    // Seções de conteúdo
    if (data.sections && data.sections.length > 0) {
      // Sobre a Wa Project (primeira seção ou seção padrão)
      this.addSectionTitle('Sobre a Wa Project')
      this.addParagraph('A Wa Project é uma software house com mais de 13 anos de experiência no desenvolvimento de soluções tecnológicas customizadas.')

      // Nossos serviços
      this.addParagraph('Nossos serviços:')
      this.addBulletList([
        'Desenvolvimento de Software.',
        'Desenvolvimento de Aplicativos.',
        'Soluções de Inteligência Artificial.',
        'Alocação de Profissionais.'
      ])

      // Nossos Clientes
      this.addSectionTitle('Nossos Clientes')
      this.addBulletList([
        'PepsiCo',
        'Vtex',
        'Santillana',
        'Dasa',
        'WideLabs',
        'Confederação Brasileira de Hipismo',
        'Forbes',
        'Easy Salon',
        'InstaCarro',
        'Antilhas',
        'Fundação Carlos Chagas',
        'Funarbe'
      ])
      this.addParagraph('Cases completos: waproject.com.br/cases')

      // Nova página para conteúdo específico do projeto
      this.newPage()
      progressCallback?.(40)

      // Processar seções da proposta com progresso
      const totalSections = data.sections.length
      data.sections.forEach((section, index) => {
        // Verificar se há espaço suficiente para iniciar uma seção
        this.checkPageBreak(25, 'section')

        this.addSectionTitle(section.title)
        this.parseMarkdownContent(section.content)
        this.currentY += 5
        this.sectionCount++

        // Atualizar progresso (40% a 80% para seções)
        const sectionProgress = 40 + (index / totalSections) * 40
        progressCallback?.(Math.round(sectionProgress))
      })
    }

    // PÁGINA FINAL: Fechamento
    this.newPage()
    progressCallback?.(80)

    // Próximos Passos
    this.addSectionTitle('Próximos Passos')
    this.addBulletList([
      'Aprovação desta proposta comercial',
      'Assinatura do contrato de prestação de serviços',
      'Kick-off do projeto',
      'Início do desenvolvimento'
    ])

    this.addParagraph('Estamos à disposição para esclarecer dúvidas e ansiosos para iniciar esta parceria!')
    progressCallback?.(90)

    // Encerramento
    this.currentY += 15

    // Citação
    this.doc.setTextColor(WA_COLORS.primary)
    this.doc.setFontSize(14)
    this.doc.setFont('helvetica', 'bold')
    const quote = 'Não é sobre desenvolvimento, é sobre envolvimento.'
    const quoteWidth = this.getTextWidthCached(quote)
    const quoteCenterX = (this.pageWidth - quoteWidth) / 2
    this.doc.text(quote, quoteCenterX, this.currentY)
    this.currentY += 10

    this.doc.setFontSize(12)
    const thanks = 'Obrigado por confiar na Wa Project!'
    const thanksWidth = this.getTextWidthCached(thanks)
    const thanksCenterX = (this.pageWidth - thanksWidth) / 2
    this.doc.text(thanks, thanksCenterX, this.currentY)
    this.currentY += 15

    // Informações da empresa customizáveis
    this.addCompanyInfo()

    this.currentY += 10

    // Validade
    this.doc.setTextColor(WA_COLORS.textMuted)
    this.doc.setFontSize(9)
    const validity = `Proposta válida por ${data.validade_dias} dias a partir da data de emissão`
    const validityWidth = this.doc.getTextWidth(validity)
    const validityCenterX = (this.pageWidth - validityWidth) / 2
    this.doc.text(validity, validityCenterX, this.currentY)

    // Adicionar rodapé na página final
    this.addFooterLogo()
  }

  private addCompanyInfo() {
    const companyInfo = this.customization.footer?.companyInfo

    if (!companyInfo) return

    // Nome da empresa
    if (companyInfo.name) {
      this.doc.setTextColor(WA_COLORS.text)
      this.doc.setFontSize(10)
      this.doc.setFont('helvetica', 'bold')
      const companyWidth = this.getTextWidthCached(companyInfo.name)
      const companyCenterX = (this.pageWidth - companyWidth) / 2
      this.doc.text(companyInfo.name, companyCenterX, this.currentY)
      this.currentY += 6
    }

    // Informações de contato
    this.doc.setFont('helvetica', 'normal')
    const infoLines = []

    if (companyInfo.cnpj) infoLines.push(`CNPJ: ${companyInfo.cnpj}`)
    if (companyInfo.website) infoLines.push(`Website: ${companyInfo.website}`)
    if (companyInfo.email) infoLines.push(`Email: ${companyInfo.email}`)
    if (companyInfo.phone) infoLines.push(`Telefone/WhatsApp: ${companyInfo.phone}`)

    infoLines.forEach(line => {
      const lineWidth = this.getTextWidthCached(line)
      const lineCenterX = (this.pageWidth - lineWidth) / 2
      this.doc.text(line, lineCenterX, this.currentY)
      this.currentY += 5
    })
  }

  public save(filename: string): void {
    this.doc.save(filename)
  }
}

// Função principal para gerar o PDF da proposta Wa Project
export function generateWaProjectProposalPDF(
  data: WaProjectProposalData,
  options?: {
    progressCallback?: (progress: number) => void
    filename?: string
    customization?: PDFCustomization
  }
): Promise<void> {
  return new Promise((resolve, reject) => {
    try {
      // Usar customização da opções ou dos dados da proposta
      const customization = options?.customization || data.customization || {}
      const generator = new WaProjectPDFGenerator(customization)

      // Usar setTimeout para tornar a geração assíncrona e não bloquear a UI
      setTimeout(() => {
        try {
          generator.generate(data, options?.progressCallback)
          options?.progressCallback?.(95)

          const filename = options?.filename ||
            `Proposta_${data.projeto.nome.replace(/[^a-zA-Z0-9]/g, '_')}_${data.data_emissao.replace(/\//g, '-')}.pdf`

          generator.save(filename)
          options?.progressCallback?.(100)

          resolve()
        } catch (error) {
          console.error('Erro ao gerar PDF da Wa Project:', error)
          reject(error)
        }
      }, 10) // Pequeno delay para permitir que a UI atualize
    } catch (error) {
      console.error('Erro ao inicializar geração de PDF da Wa Project:', error)
      reject(error)
    }
  })
}

