import jsPDF from 'jspdf'
import type { ProposalSection } from './proposal-types'

// Logo da Wa Project - versão hexagonal conforme HTML template
const WA_PROJECT_LOGO_BASE64 = `data:image/svg+xml;base64,`

// Cores extraídas do template HTML para máxima fidelidade
const WA_COLORS = {
  primary: '#003B71', // --wa-brand-primary do CSS
  secondary: '#0056A3', // --wa-brand-secondary do CSS
  accent: '#E8F0FE', // --wa-brand-accent do CSS
  text: '#1f2937', // text-foreground do template
  textMuted: '#6b7280', // text-muted-foreground do template
  border: '#e5e7eb', // border do template
  background: '#f8f9fa', // bg-card do template
}

// Interface para configuração de header/footer customizáveis
interface PDFCustomization {
  header?: {
    showLogo?: boolean
    showDate?: boolean
    customText?: string
    logoSize?: { width: number; height: number }
  }
  footer?: {
    showLogo?: boolean
    showPageNumber?: boolean
    customText?: string
    companyInfo?: {
      name?: string
      cnpj?: string
      website?: string
      email?: string
      phone?: string
    }
  }
}

// Interface para os dados da proposta
interface WaProjectProposalData {
  projeto: {
    nome: string
  }
  data_emissao: string
  validade_dias: string
  cliente: {
    nome: string
  }
  tipo_escopo: string
  sections: ProposalSection[]
  numeracao_pagina: string
  customization?: PDFCustomization
}

// Classe principal para geração de PDF
export class WaProjectPDFGenerator {
  private doc: jsPDF
  private currentY: number
  private pageNumber: number
  private sectionCount: number = 0
  private estimatedHeight: number = 0
  private customization: PDFCustomization

  // Configurações de página (A4) seguindo o PDF oficial
  private readonly pageWidth = 210
  private readonly pageHeight = 297
  private readonly margin = {
    top: 25, // Margem superior conforme PDF
    right: 25, // Margem direita conforme PDF
    bottom: 25, // Margem inferior conforme PDF
    left: 25, // Margem esquerda conforme PDF
  }

  // Cache para otimização de medidas de texto
  private textWidthCache: Map<string, number> = new Map()

  constructor(customization: PDFCustomization = {}) {
    this.doc = new jsPDF({
      orientation: 'portrait',
      unit: 'mm',
      format: 'a4',
      compress: true, // Ativar compressão para PDFs grandes
      putOnlyUsedFonts: true, // Incluir apenas fontes utilizadas
      precision: 2 // Precisão de coordenadas para otimização
    })
    this.currentY = this.margin.top
    this.pageNumber = 1
    this.customization = {
      header: {
        showLogo: true,
        showDate: true,
        logoSize: { width: 25, height: 22 },
        ...customization.header
      },
      footer: {
        showLogo: true,
        showPageNumber: true,
        companyInfo: {
          name: 'Wa Project Soluções Tecnológicas LTDA.',
          cnpj: '19.317.018/0001-40',
          website: 'waproject.com.br',
          email: 'comercial@waproject.com.br',
          phone: '(11) 5028-2010'
        },
        ...customization.footer
      }
    }

    // Configurar fonte e codificação
    this.setupFonts()
  }

  private setupFonts() {
    // Configurar fonte padrão com suporte a UTF-8
    this.doc.setFont('helvetica')

    // Definir propriedades de documento para UTF-8
    this.doc.setProperties({
      title: 'Proposta Comercial Wa Project',
      creator: 'Wa Project PDF Generator',
      author: 'Wa Project',
      keywords: 'proposta, comercial, wa project',
      subject: 'Proposta Comercial'
    })

    // Configurar codificação de texto para caracteres especiais
    this.doc.setCharSpace(0)
    this.doc.setWordSpace(0)
  }

  private get contentWidth() {
    return this.pageWidth - this.margin.left - this.margin.right
  }

  private get contentStartX() {
    return this.margin.left
  }

  // Método otimizado para obter largura de texto com cache
  private getTextWidthCached(text: string): number {
    const key = `${text}_${this.doc.getFontSize()}_${this.doc.getFont().fontName}_${this.doc.getFont().fontStyle}`

    if (this.textWidthCache.has(key)) {
      return this.textWidthCache.get(key)!
    }

    const width = this.doc.getTextWidth(text)
    this.textWidthCache.set(key, width)
    return width
  }

  // Estimar altura total da proposta (para otimizar alocação de páginas)
  private estimateTotalHeight(data: WaProjectProposalData): number {
    let estimated = 100 // Capa base

    // Estimativa baseada no número de seções e conteúdo
    if (data.sections && data.sections.length > 0) {
      data.sections.forEach(section => {
        estimated += 15 // Título da seção
        estimated += section.content.split('\n').length * 6 // Aproximação do conteúdo
        estimated += 10 // Espaçamento entre seções
      })
    }

    estimated += 60 // Páginas finais fixas (próximos passos, encerramento)

    return estimated
  }

  // Otimização para renderização em lote
  private batchRenderItems<T>(
    items: T[],
    renderFn: (item: T, index: number) => void,
    batchSize: number = 10
  ): void {
    for (let i = 0; i < items.length; i += batchSize) {
      const batch = items.slice(i, i + batchSize)
      batch.forEach((item, index) => renderFn(item, i + index))

      // Yield para não bloquear a UI em listas muito grandes
      if (i + batchSize < items.length && items.length > 50) {
        setTimeout(() => {}, 0)
      }
    }
  }

  private addWatermark() {
    // Marca d'água do logo Wa Project no centro da página
    const watermarkX = this.pageWidth / 2 - 30
    const watermarkY = this.pageHeight / 2 - 30

    try {
      this.doc.addImage(
        WA_PROJECT_LOGO_BASE64,
        'SVG',
        watermarkX,
        watermarkY,
        60, // largura da marca d'água
        52, // altura da marca d'água
        undefined,
        'FAST'
      )

      // Definir opacidade baixa para marca d'água
      this.doc.setGState(this.doc.GState({opacity: 0.05}))

      // Voltar opacidade normal
      this.doc.setGState(this.doc.GState({opacity: 1.0}))
    } catch (error) {
      // Fallback: marca d'água textual
      this.doc.setTextColor('#E8E8E8')
      this.doc.setFontSize(48)
      this.doc.setFont('helvetica', 'bold')
      this.doc.text('Wa Project', watermarkX, watermarkY, {
        angle: 45,
        align: 'center'
      })
    }
  }

  private addHeader(data?: WaProjectProposalData) {
    if (!this.customization.header?.showLogo && !this.customization.header?.customText) {
      return
    }

    const headerStartY = this.currentY

    // Logo customizável
    if (this.customization.header?.showLogo) {
      try {
        const logoSize = this.customization.header.logoSize || { width: 25, height: 22 }
        this.doc.addImage(
          WA_PROJECT_LOGO_BASE64,
          'SVG',
          this.contentStartX,
          headerStartY,
          logoSize.width,
          logoSize.height,
          undefined,
          'FAST'
        )
      } catch (error) {
        // Fallback: logo textual
        this.doc.setFillColor(WA_COLORS.primary)
        this.doc.roundedRect(this.contentStartX, headerStartY, 25, 10, 2, 2, 'F')

        this.doc.setTextColor('#ffffff')
        this.doc.setFontSize(10)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text('Wa Project', this.contentStartX + 3, headerStartY + 7)
      }
    }

    // Texto customizado no header
    if (this.customization.header?.customText) {
      this.doc.setTextColor(WA_COLORS.primary)
      this.doc.setFontSize(10)
      this.doc.setFont('helvetica', 'normal')
      const textWidth = this.getTextWidthCached(this.customization.header.customText)
      const textX = this.pageWidth - this.margin.right - textWidth
      this.doc.text(this.customization.header.customText, textX, headerStartY + 15)
    }

    // Data no header (se configurado)
    if (this.customization.header?.showDate && data) {
      this.doc.setTextColor(WA_COLORS.textMuted)
      this.doc.setFontSize(9)
      this.doc.setFont('helvetica', 'normal')
      const dateText = `Data: ${data.data_emissao}`
      const textWidth = this.getTextWidthCached(dateText)
      const textX = this.pageWidth - this.margin.right - textWidth
      this.doc.text(dateText, textX, headerStartY + 6)
    }

    this.currentY = headerStartY + 30
  }

  // Manter compatibilidade com método original
  private addLogo() {
    this.addHeader()
  }

  private addTitle(title: string, subtitle?: string) {
    // Título principal conforme PDF
    this.doc.setTextColor(WA_COLORS.primary)
    this.doc.setFontSize(28)
    this.doc.setFont('helvetica', 'bold')

    this.doc.text(title, this.contentStartX, this.currentY)
    this.currentY += 15

    // Subtítulo do projeto conforme PDF
    if (subtitle) {
      this.doc.setFontSize(22)
      this.doc.setFont('helvetica', 'bold')
      this.doc.setTextColor(WA_COLORS.primary)
      this.doc.text(subtitle, this.contentStartX, this.currentY)
      this.currentY += 12
    }

    this.currentY += 8
  }

  private addCoverInfo(data: WaProjectProposalData) {
    // Centralizar informações
    this.doc.setTextColor(WA_COLORS.text)
    this.doc.setFontSize(11)
    this.doc.setFont('helvetica', 'normal')

    const infoLines = [
      `${data.data_emissao} | Válido por ${data.validade_dias} dias`,
      `Para: ${data.cliente.nome}`,
      `Tipo: ${data.tipo_escopo}`
    ]

    infoLines.forEach(line => {
      const lineWidth = this.getTextWidthCached(line)
      const centerX = (this.pageWidth - lineWidth) / 2
      this.doc.text(line, centerX, this.currentY)
      this.currentY += 6
    })

    this.currentY += 15
  }

  private checkPageBreak(neededHeight: number, context: 'title' | 'paragraph' | 'list' | 'section' = 'paragraph'): boolean {
    const availableSpace = this.pageHeight - this.margin.bottom - 15 - this.currentY

    // Se não cabe de forma alguma, quebra a página
    if (neededHeight > availableSpace) {
      this.addPageNumber()
      this.newPage()
      return true
    }

    // Lógica inteligente baseada no contexto
    switch (context) {
      case 'title':
        // Títulos precisam de pelo menos 20mm de espaço após eles para evitar órfãos
        if (availableSpace < neededHeight + 20) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break

      case 'section':
        // Seções precisam de pelo menos 30mm de espaço para não quebrar no início
        if (availableSpace < neededHeight + 30) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break

      case 'list':
        // Listas pequenas (até 3 itens) não devem quebrar
        if (neededHeight <= 25 && availableSpace < neededHeight) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break

      case 'paragraph':
      default:
        // Parágrafos pequenos (até 15mm) não devem quebrar
        if (neededHeight <= 15 && availableSpace < neededHeight) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break
    }

    return false
  }

  private newPage() {
    this.doc.addPage()
    this.pageNumber++
    this.currentY = this.margin.top + 5
    this.addWatermark()
    this.addFooterLogo()
  }

  private addCustomFooter() {
    const footerY = this.pageHeight - 15

    // Logo customizável no rodapé
    if (this.customization.footer?.showLogo) {
      try {
        this.doc.addImage(
          WA_PROJECT_LOGO_BASE64,
          'SVG',
          this.contentStartX,
          footerY - 10,
          20,
          8,
          undefined,
          'FAST'
        )
      } catch (error) {
        // Fallback textual
        this.doc.setTextColor(WA_COLORS.primary)
        this.doc.setFontSize(8)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text('Wa Project', this.contentStartX, footerY)
      }
    }

    // Texto customizado no rodapé (centro)
    if (this.customization.footer?.customText) {
      this.doc.setTextColor(WA_COLORS.textMuted)
      this.doc.setFontSize(8)
      this.doc.setFont('helvetica', 'normal')
      const textWidth = this.getTextWidthCached(this.customization.footer.customText)
      const centerX = (this.pageWidth - textWidth) / 2
      this.doc.text(this.customization.footer.customText, centerX, footerY)
    }

    // Número da página customizável (direita)
    if (this.customization.footer?.showPageNumber) {
      this.doc.setTextColor(WA_COLORS.primary)
      this.doc.setFontSize(10)
      this.doc.setFont('helvetica', 'normal')
      this.doc.text(
        this.pageNumber.toString(),
        this.pageWidth - this.margin.right,
        footerY,
        { align: 'right' }
      )
    }
  }

  // Manter compatibilidade com método original
  private addFooterLogo() {
    this.addCustomFooter()
  }

  private addPageNumber() {
    this.doc.setFontSize(9)
    this.doc.setTextColor(WA_COLORS.textMuted)
    this.doc.text(
      this.pageNumber.toString(),
      this.pageWidth / 2,
      this.pageHeight - 10,
      { align: 'center' }
    )
  }

  private addSectionTitle(title: string) {
    this.checkPageBreak(15, 'title')

    this.doc.setTextColor(WA_COLORS.primary)
    this.doc.setFontSize(16)
    this.doc.setFont('helvetica', 'bold')
    this.doc.text(title, this.contentStartX, this.currentY)
    this.currentY += 12
  }

  private addParagraph(text: string) {
    this.doc.setTextColor(WA_COLORS.text)
    this.doc.setFontSize(11)
    this.doc.setFont('helvetica', 'normal')

    const lines = this.doc.splitTextToSize(text, this.contentWidth)

    // Calcular altura total do parágrafo
    const totalParagraphHeight = lines.length * 6 + 4

    // Verificar se o parágrafo inteiro cabe na página
    this.checkPageBreak(totalParagraphHeight, 'paragraph')

    lines.forEach((line: string) => {
      this.doc.text(line, this.contentStartX, this.currentY)
      this.currentY += 6
    })

    this.currentY += 4
  }

  private addBulletList(items: string[]) {
    // Calcular altura estimada da lista completa
    const estimatedListHeight = items.length * 8
    this.checkPageBreak(estimatedListHeight, 'list')

    // Para listas grandes, usar renderização em lote
    if (items.length > 20) {
      this.batchRenderItems(items, (item, index) => {
        this.renderBulletItem(item)
      })
    } else {
      // Para listas pequenas, renderização direta
      items.forEach(item => {
        this.renderBulletItem(item)
      })
    }
  }

  private renderBulletItem(item: string) {
    // Para itens individuais, usar contexto de parágrafo
    this.checkPageBreak(8, 'paragraph')

    // Bullet point
    this.doc.setTextColor(WA_COLORS.primary)
    this.doc.text('•', this.contentStartX, this.currentY)

    // Texto do item
    this.doc.setTextColor(WA_COLORS.textMuted)
    this.doc.setFontSize(10)
    this.doc.setFont('helvetica', 'normal')

    const lines = this.doc.splitTextToSize(item, this.contentWidth - 8)
    lines.forEach((line: string, lineIndex: number) => {
      if (lineIndex > 0) this.checkPageBreak(5, 'paragraph')
      this.doc.text(line, this.contentStartX + 6, this.currentY)
      if (lineIndex < lines.length - 1) this.currentY += 5
    })

    this.currentY += 6
  }

  private parseMarkdownContent(content: string): void {
    const lines = content.split('\n')

    for (const line of lines) {
      const trimmed = line.trim()

      if (!trimmed) {
        this.currentY += 3
        continue
      }

      // Títulos
      if (trimmed.startsWith('### ') || trimmed.startsWith('## ') || trimmed.startsWith('# ')) {
        const titleText = trimmed.replace(/^#+\s+/, '')

        // Verificar quebra de página para títulos
        this.checkPageBreak(8, 'title')

        this.doc.setTextColor(WA_COLORS.primary)
        this.doc.setFontSize(12)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text(titleText, this.contentStartX, this.currentY)
        this.currentY += 8
        continue
      }

      // Listas com bullets
      if (trimmed.startsWith('• ') || trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
        const itemText = trimmed.slice(2).replace(/\*\*(.*?)\*\*/g, '$1')
        this.addBulletList([itemText])
        continue
      }

      // Listas numeradas
      const numberedMatch = trimmed.match(/^(\d+)\.\s+(.+)$/)
      if (numberedMatch) {
        const itemText = numberedMatch[2].replace(/\*\*(.*?)\*\*/g, '$1')

        this.checkPageBreak(8, 'paragraph')
        this.doc.setTextColor(WA_COLORS.primary)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text(`${numberedMatch[1]}.`, this.contentStartX, this.currentY)

        this.doc.setTextColor(WA_COLORS.textMuted)
        this.doc.setFont('helvetica', 'normal')
        this.doc.text(itemText, this.contentStartX + 8, this.currentY)
        this.currentY += 6
        continue
      }

      // Parágrafos regulares
      if (trimmed && !trimmed.startsWith('-') && !trimmed.startsWith('|')) {
        const plainText = trimmed.replace(/\*\*(.*?)\*\*/g, '$1')
        this.addParagraph(plainText)
      }
    }
  }

  public generate(data: WaProjectProposalData, progressCallback?: (progress: number) => void): void {
    // Estimar altura total para otimização
    this.estimatedHeight = this.estimateTotalHeight(data)

    // Adicionar marca d'água na primeira página
    this.addWatermark()
    progressCallback?.(5)

    // PÁGINA 1: CAPA
    this.addHeader(data)
    this.addTitle('Proposta Comercial', data.projeto.nome)
    this.addCoverInfo(data)
    progressCallback?.(15)

    // Seções de conteúdo
    if (data.sections && data.sections.length > 0) {
      // Sobre a Wa Project (primeira seção ou seção padrão)
      this.addSectionTitle('Sobre a Wa Project')
      this.addParagraph('A Wa Project é uma software house com mais de 13 anos de experiência no desenvolvimento de soluções tecnológicas customizadas.')

      // Nossos serviços
      this.addParagraph('Nossos serviços:')
      this.addBulletList([
        'Desenvolvimento de Software.',
        'Desenvolvimento de Aplicativos.',
        'Soluções de Inteligência Artificial.',
        'Alocação de Profissionais.'
      ])

      // Nossos Clientes
      this.addSectionTitle('Nossos Clientes')
      this.addBulletList([
        'PepsiCo',
        'Vtex',
        'Santillana',
        'Dasa',
        'WideLabs',
        'Confederação Brasileira de Hipismo',
        'Forbes',
        'Easy Salon',
        'InstaCarro',
        'Antilhas',
        'Fundação Carlos Chagas',
        'Funarbe'
      ])
      this.addParagraph('Cases completos: waproject.com.br/cases')

      // Nova página para conteúdo específico do projeto
      this.newPage()
      progressCallback?.(40)

      // Processar seções da proposta com progresso
      const totalSections = data.sections.length
      data.sections.forEach((section, index) => {
        // Verificar se há espaço suficiente para iniciar uma seção
        this.checkPageBreak(25, 'section')

        this.addSectionTitle(section.title)
        this.parseMarkdownContent(section.content)
        this.currentY += 5
        this.sectionCount++

        // Atualizar progresso (40% a 80% para seções)
        const sectionProgress = 40 + (index / totalSections) * 40
        progressCallback?.(Math.round(sectionProgress))
      })
    }

    // PÁGINA FINAL: Fechamento
    this.newPage()
    progressCallback?.(80)

    // Próximos Passos
    this.addSectionTitle('Próximos Passos')
    this.addBulletList([
      'Aprovação desta proposta comercial',
      'Assinatura do contrato de prestação de serviços',
      'Kick-off do projeto',
      'Início do desenvolvimento'
    ])

    this.addParagraph('Estamos à disposição para esclarecer dúvidas e ansiosos para iniciar esta parceria!')
    progressCallback?.(90)

    // Encerramento
    this.currentY += 15

    // Citação
    this.doc.setTextColor(WA_COLORS.primary)
    this.doc.setFontSize(14)
    this.doc.setFont('helvetica', 'bold')
    const quote = 'Não é sobre desenvolvimento, é sobre envolvimento.'
    const quoteWidth = this.getTextWidthCached(quote)
    const quoteCenterX = (this.pageWidth - quoteWidth) / 2
    this.doc.text(quote, quoteCenterX, this.currentY)
    this.currentY += 10

    this.doc.setFontSize(12)
    const thanks = 'Obrigado por confiar na Wa Project!'
    const thanksWidth = this.getTextWidthCached(thanks)
    const thanksCenterX = (this.pageWidth - thanksWidth) / 2
    this.doc.text(thanks, thanksCenterX, this.currentY)
    this.currentY += 15

    // Informações da empresa customizáveis
    this.addCompanyInfo()

    this.currentY += 10

    // Validade
    this.doc.setTextColor(WA_COLORS.textMuted)
    this.doc.setFontSize(9)
    const validity = `Proposta válida por ${data.validade_dias} dias a partir da data de emissão`
    const validityWidth = this.doc.getTextWidth(validity)
    const validityCenterX = (this.pageWidth - validityWidth) / 2
    this.doc.text(validity, validityCenterX, this.currentY)

    // Adicionar rodapé na página final
    this.addFooterLogo()
  }

  private addCompanyInfo() {
    const companyInfo = this.customization.footer?.companyInfo

    if (!companyInfo) return

    // Nome da empresa
    if (companyInfo.name) {
      this.doc.setTextColor(WA_COLORS.text)
      this.doc.setFontSize(10)
      this.doc.setFont('helvetica', 'bold')
      const companyWidth = this.getTextWidthCached(companyInfo.name)
      const companyCenterX = (this.pageWidth - companyWidth) / 2
      this.doc.text(companyInfo.name, companyCenterX, this.currentY)
      this.currentY += 6
    }

    // Informações de contato
    this.doc.setFont('helvetica', 'normal')
    const infoLines = []

    if (companyInfo.cnpj) infoLines.push(`CNPJ: ${companyInfo.cnpj}`)
    if (companyInfo.website) infoLines.push(`Website: ${companyInfo.website}`)
    if (companyInfo.email) infoLines.push(`Email: ${companyInfo.email}`)
    if (companyInfo.phone) infoLines.push(`Telefone/WhatsApp: ${companyInfo.phone}`)

    infoLines.forEach(line => {
      const lineWidth = this.getTextWidthCached(line)
      const lineCenterX = (this.pageWidth - lineWidth) / 2
      this.doc.text(line, lineCenterX, this.currentY)
      this.currentY += 5
    })
  }

  public save(filename: string): void {
    this.doc.save(filename)
  }
}

// Função principal para gerar o PDF da proposta Wa Project
export function generateWaProjectProposalPDF(
  data: WaProjectProposalData,
  options?: {
    progressCallback?: (progress: number) => void
    filename?: string
    customization?: PDFCustomization
  }
): Promise<void> {
  return new Promise((resolve, reject) => {
    try {
      // Usar customização da opções ou dos dados da proposta
      const customization = options?.customization || data.customization || {}
      const generator = new WaProjectPDFGenerator(customization)

      // Usar setTimeout para tornar a geração assíncrona e não bloquear a UI
      setTimeout(() => {
        try {
          generator.generate(data, options?.progressCallback)
          options?.progressCallback?.(95)

          const filename = options?.filename ||
            `Proposta_${data.projeto.nome.replace(/[^a-zA-Z0-9]/g, '_')}_${data.data_emissao.replace(/\//g, '-')}.pdf`

          generator.save(filename)
          options?.progressCallback?.(100)

          resolve()
        } catch (error) {
          console.error('Erro ao gerar PDF da Wa Project:', error)
          reject(error)
        }
      }, 10) // Pequeno delay para permitir que a UI atualize
    } catch (error) {
      console.error('Erro ao inicializar geração de PDF da Wa Project:', error)
      reject(error)
    }
  })
}

