/**
 * Testes para geração de PDF do template de proposta Wa Project
 */

import { WaProjectPDFGenerator, generateWaProjectProposalPDF } from '../wa-project-pdf-generator'
import type { WaProjectProposalData } from '../wa-project-pdf-generator'

// Mock do jsPDF
jest.mock('jspdf', () => {
  return jest.fn().mockImplementation(() => ({
    addPage: jest.fn(),
    setFont: jest.fn(),
    setFontSize: jest.fn(),
    setTextColor: jest.fn(),
    setFillColor: jest.fn(),
    text: jest.fn(),
    addImage: jest.fn(),
    splitTextToSize: jest.fn().mockReturnValue(['mocked line 1', 'mocked line 2']),
    getTextWidth: jest.fn().mockReturnValue(50),
    roundedRect: jest.fn(),
    setProperties: jest.fn(),
    setCharSpace: jest.fn(),
    setWordSpace: jest.fn(),
    setGState: jest.fn().mockReturnValue({ GState: jest.fn() }),
    GState: jest.fn(),
    save: jest.fn()
  }))
})

describe('WaProjectPDFGenerator', () => {
  let mockData: WaProjectProposalData

  beforeEach(() => {
    mockData = {
      projeto: {
        nome: 'Projeto de Teste'
      },
      data_emissao: '30/03/2026',
      validade_dias: '15',
      cliente: {
        nome: 'Cliente Teste LTDA'
      },
      tipo_escopo: 'Escopo fechado',
      sections: [
        {
          title: 'Seção de Teste',
          content: 'Conteúdo de teste da seção'
        }
      ],
      numeracao_pagina: '1'
    }
  })

  describe('Inicialização', () => {
    it('deve inicializar corretamente com configurações padrão', () => {
      const generator = new WaProjectPDFGenerator()
      expect(generator).toBeDefined()
    })

    it('deve inicializar com customização personalizada', () => {
      const customization = {
        header: {
          showLogo: false,
          customText: 'Header customizado'
        },
        footer: {
          showPageNumber: false,
          customText: 'Footer customizado'
        }
      }

      const generator = new WaProjectPDFGenerator(customization)
      expect(generator).toBeDefined()
    })
  })

  describe('Sanitização de texto', () => {
    let generator: WaProjectPDFGenerator

    beforeEach(() => {
      generator = new WaProjectPDFGenerator()
    })

    it('deve sanitizar caracteres especiais corretamente', () => {
      // Testando função privada através da geração
      const dataWithSpecialChars = {
        ...mockData,
        sections: [{
          title: 'Título com "aspas curvadas" e caracteres—especiais',
          content: 'Conteúdo com áçêñtós e caracteres…especiais'
        }]
      }

      expect(() => {
        generator.generate(dataWithSpecialChars)
      }).not.toThrow()
    })

    it('deve lidar com texto null/undefined', () => {
      const dataWithNullContent = {
        ...mockData,
        sections: [{
          title: '',
          content: ''
        }]
      }

      expect(() => {
        generator.generate(dataWithNullContent)
      }).not.toThrow()
    })
  })

  describe('Geração de PDF', () => {
    it('deve gerar PDF sem callback de progresso', async () => {
      await expect(generateWaProjectProposalPDF(mockData)).resolves.toBeUndefined()
    })

    it('deve gerar PDF com callback de progresso', async () => {
      const progressCallback = jest.fn()

      await generateWaProjectProposalPDF(mockData, {
        progressCallback,
        filename: 'teste.pdf'
      })

      expect(progressCallback).toHaveBeenCalled()
      // Verificar se foi chamado com valores entre 0 e 100
      const calls = progressCallback.mock.calls.map(call => call[0])
      expect(calls.every(progress => progress >= 0 && progress <= 100)).toBe(true)
