      const largeFeatureList = Array.from({ length: 50 }, (_, i) => ({
        numero: i + 1,
        titulo: `Funcionalidade ${i + 1}`,
        descricao: `Descrição da funcionalidade ${i + 1}`
      }))

      const dataWithManyFeatures = {
        ...mockData,
        funcionalidades: {
          titulo: 'Funcionalidades',
          itens: largeFeatureList
