      expect(container.firstChild).toBeInTheDocument()

      // Verificar que algumas funcionalidades foram renderizadas
      expect(screen.getByText('1. Funcionalidade 1')).toBeInTheDocument()
      expect(screen.getByText('50. Funcionalidade 50')).toBeInTheDocument()
    })

    it('deve usar React.memo para itens de funcionalidades', () => {
      // Este teste verifica se a estrutura está correta para otimização
      const dataWithFeatures = {
        ...mockData,
        funcionalidades: {
          titulo: 'Funcionalidades',
          itens: [
            {
              numero: 1,
              titulo: 'Funcionalidade Teste',
              descricao: 'Descrição de teste'
            }
          ]
        }
      }

      expect(() => {
        render(<ProposalTemplateRenderer data={dataWithFeatures} />)
      }).not.toThrow()
    })
  })

  describe('Acessibilidade', () => {
    it('deve ter estrutura semântica correta', () => {
      render(<ProposalTemplateRenderer data={mockData} />)

      // Verificar se há headers estruturados
      const headers = screen.getAllByRole('heading')
      expect(headers.length).toBeGreaterThan(0)
    })

    it('deve ter listas estruturadas corretamente', () => {
      const dataWithLists = {
        ...mockData,
        empresa: {
          ...mockData.empresa,
          servicos: ['Desenvolvimento Web', 'Consultoria'],
          clientes: ['Cliente A', 'Cliente B']
        }
      }

      render(<ProposalTemplateRenderer data={dataWithLists} />)

      const lists = screen.getAllByRole('list')
      expect(lists.length).toBeGreaterThan(0)
    })
  })

  describe('Tratamento de dados faltantes', () => {
    it('deve lidar com seções opcionais ausentes', () => {
      const minimalData = {
        ...mockData,
        integracoes: undefined,
        cronograma: {
          ...mockData.cronograma,
          fases: undefined
        }
      }

      expect(() => {
        render(<ProposalTemplateRenderer data={minimalData} />)
      }).not.toThrow()
    })

    it('deve renderizar com dados mínimos', () => {
      const minimalData = {
        capa: mockData.capa,
        empresa: mockData.empresa,
        projeto: mockData.projeto,
        funcionalidades: { titulo: 'Funcionalidades', itens: [] },
        modeloTrabalho: mockData.modeloTrabalho,
        equipe: mockData.equipe,
        cronograma: mockData.cronograma,
        investimento: mockData.investimento,
        entregaveis: mockData.entregaveis,
        proximosPassos: mockData.proximosPassos,
        encerramento: mockData.encerramento
      }

      render(<ProposalTemplateRenderer data={minimalData} />)

      expect(screen.getByText('Proposta Comercial')).toBeInTheDocument()
    })
  })

  describe('Customização', () => {
    it('deve aplicar className customizado', () => {
      const customClass = 'custom-proposal-class'
      const { container } = render(
        <ProposalTemplateRenderer data={mockData} className={customClass} />
      )

      expect(container.firstChild).toHaveClass(customClass)
    })

    it('deve manter classes padrão com className customizado', () => {
      const customClass = 'custom-class'
      const { container } = render(
        <ProposalTemplateRenderer data={mockData} className={customClass} />
      )

      const element = container.firstChild as HTMLElement
      expect(element).toHaveClass('w-full')
      expect(element).toHaveClass('max-w-[210mm]')
      expect(element).toHaveClass(customClass)
    })
  })
})

