export function generateWaProjectProposalPDF(
  data: WaProjectProposalData,
  options?: {
    progressCallback?: (progress: number) => void
    filename?: string
    customization?: PDFCustomization
    skipValidation?: boolean
    onValidationWarnings?: (warnings: string[]) => void
  }
): Promise<void> {
  return new Promise((resolve, reject) => {
    try {
      // Validar dados antes de gerar (opcional)
      if (!options?.skipValidation) {
        const validation = validateProposalData(data)

        if (!validation.valid) {
          const errorMessage = `Validação falhou: ${validation.errors.map(e => `${e.field}: ${e.message}`).join(', ')}`
          reject(new Error(errorMessage))
          return
        }

        // Reportar warnings se callback fornecido
        if (validation.warnings.length > 0 && options?.onValidationWarnings) {
          options.onValidationWarnings(validation.warnings)
        }
      }

      // Usar customização da opções ou dos dados da proposta
      const customization = options?.customization || data.customization || {}
      const generator = new WaProjectPDFGenerator(customization)

      // Usar setTimeout para tornar a geração assíncrona e não bloquear a UI
      setTimeout(() => {
        try {
          generator.generate(data, options?.progressCallback)
          options?.progressCallback?.(95)

          // Sanitizar nome do arquivo
          const sanitizedProjectName = data.projeto.nome
            .replace(/[^a-zA-Z0-9\-_\s]/g, '') // Remove caracteres especiais
            .replace(/\s+/g, '_') // Substitui espaços por underscore
            .substring(0, 50) // Limita tamanho

          const sanitizedDate = data.data_emissao.replace(/\//g, '-')

          const filename = options?.filename ||
            `Proposta_${sanitizedProjectName}_${sanitizedDate}.pdf`

          generator.save(filename)
          options?.progressCallback?.(100)

