// Função para sanitizar dados da proposta antes da geração
export function sanitizeProposalData(data: WaProjectProposalData): WaProjectProposalData {
  const sanitized = JSON.parse(JSON.stringify(data)) // Deep clone

  // Sanitizar strings removendo caracteres problemáticos
  const sanitizeString = (str: string): string => {
    if (!str || typeof str !== 'string') return ''

    return str
      // Normalizar espaços
      .replace(/\s+/g, ' ')
      .trim()
      // Remover caracteres de controle
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
      // Limitar tamanho para evitar problemas
      .substring(0, 5000)
  }

  // Sanitizar campos principais
  if (sanitized.projeto?.nome) {
    sanitized.projeto.nome = sanitizeString(sanitized.projeto.nome)
  }

  if (sanitized.cliente?.nome) {
    sanitized.cliente.nome = sanitizeString(sanitized.cliente.nome)
  }

  if (sanitized.tipo_escopo) {
    sanitized.tipo_escopo = sanitizeString(sanitized.tipo_escopo)
  }

  // Sanitizar seções
  if (sanitized.sections && Array.isArray(sanitized.sections)) {
    sanitized.sections = sanitized.sections.map(section => ({
      ...section,
      title: sanitizeString(section.title || ''),
      content: sanitizeString(section.content || '')
    })).filter(section => section.title || section.content) // Remove seções vazias
  }

  // Validar e corrigir data
  if (sanitized.data_emissao) {
    const dateRegex = /^\d{2}\/\d{2}\/\d{4}$/
    if (!dateRegex.test(sanitized.data_emissao)) {
      // Tentar corrigir formato de data comum
      const dateStr = sanitized.data_emissao.replace(/[-\.]/g, '/')
      if (dateRegex.test(dateStr)) {
        sanitized.data_emissao = dateStr
      } else {
        // Usar data atual como fallback
        const today = new Date()
        sanitized.data_emissao = today.toLocaleDateString('pt-BR')
      }
    }
  }

  // Validar e corrigir validade
  if (sanitized.validade_dias) {
    const days = parseInt(sanitized.validade_dias.toString(), 10)
    if (isNaN(days) || days <= 0) {
      sanitized.validade_dias = '30' // Padrão de 30 dias
    } else if (days > 365) {
      sanitized.validade_dias = '365' // Máximo de 1 ano
    }
  }

  return sanitized
}

