      }
      break

    case 'cliente.nome':
      if (!value || typeof value !== 'string' || value.trim().length === 0) {
        return { field: fieldName, message: 'Nome do cliente é obrigatório' }
      }
      if (value.length > 200) {
        return { field: fieldName, message: 'Nome do cliente muito longo (máximo 200 caracteres)' }
      }
      break

    case 'data_emissao':
      if (!value || typeof value !== 'string' || value.trim().length === 0) {
        return { field: fieldName, message: 'Data de emissão é obrigatória' }
      }
      const dateRegex = /^\d{2}\/\d{2}\/\d{4}$/
      if (!dateRegex.test(value)) {
        return { field: fieldName, message: 'Data deve estar no formato DD/MM/YYYY' }
      }
      break

    case 'validade_dias':
      const days = parseInt(value?.toString() || '', 10)
      if (isNaN(days) || days <= 0) {
        return { field: fieldName, message: 'Validade deve ser um número positivo' }
      }
      if (days > 365) {
        return { field: fieldName, message: 'Validade máxima é de 365 dias' }
      }
      break

    case 'tipo_escopo':
      if (!value || typeof value !== 'string' || value.trim().length === 0) {
        return { field: fieldName, message: 'Tipo de escopo é obrigatório' }
      }
      break

    default:
      break
  }

  return null
}

