import jsPDF from 'jspdf'
import type { ProposalSection } from './proposal-types'

// Função de validação abrangente para dados da proposta
export function validateProposalData(data: any): ValidationResult {
  const errors: ValidationError[] = []
  const warnings: string[] = []

  // Verificar se data existe
  if (!data) {
    return {
      valid: false,
      errors: [{ field: 'data', message: 'Dados da proposta não fornecidos' }],
      warnings: []
    }
  }

  // Validar projeto
  if (!data.projeto) {
    errors.push({ field: 'projeto', message: 'Informações do projeto são obrigatórias' })
  } else {
    if (!data.projeto.nome || typeof data.projeto.nome !== 'string' || data.projeto.nome.trim().length === 0) {
      errors.push({ field: 'projeto.nome', message: 'Nome do projeto é obrigatório' })
    } else if (data.projeto.nome.length > 200) {
      warnings.push('Nome do projeto muito longo (>200 caracteres), pode ser truncado no PDF')
    }
  }

  // Validar data de emissão
  if (!data.data_emissao || typeof data.data_emissao !== 'string' || data.data_emissao.trim().length === 0) {
    errors.push({ field: 'data_emissao', message: 'Data de emissão é obrigatória' })
  } else {
    // Validar formato de data (DD/MM/YYYY)
    const dateRegex = /^\d{2}\/\d{2}\/\d{4}$/
    if (!dateRegex.test(data.data_emissao)) {
      errors.push({ field: 'data_emissao', message: 'Data de emissão deve estar no formato DD/MM/YYYY' })
    } else {
      // Validar se é uma data válida
      const [day, month, year] = data.data_emissao.split('/').map(Number)
      const date = new Date(year, month - 1, day)
      if (date.getDate() !== day || date.getMonth() !== month - 1 || date.getFullYear() !== year) {
        errors.push({ field: 'data_emissao', message: 'Data de emissão inválida' })
      }
    }
  }

  // Validar validade em dias
  if (!data.validade_dias || typeof data.validade_dias !== 'string' || data.validade_dias.trim().length === 0) {
    errors.push({ field: 'validade_dias', message: 'Validade em dias é obrigatória' })
  } else {
    const days = parseInt(data.validade_dias, 10)
    if (isNaN(days) || days <= 0) {
      errors.push({ field: 'validade_dias', message: 'Validade deve ser um número positivo' })
    } else if (days > 365) {
      warnings.push('Validade muito alta (>365 dias), verifique se está correto')
    }
  }

  // Validar cliente
  if (!data.cliente) {
    errors.push({ field: 'cliente', message: 'Informações do cliente são obrigatórias' })
  } else {
    if (!data.cliente.nome || typeof data.cliente.nome !== 'string' || data.cliente.nome.trim().length === 0) {
      errors.push({ field: 'cliente.nome', message: 'Nome do cliente é obrigatório' })
    } else if (data.cliente.nome.length > 200) {
      warnings.push('Nome do cliente muito longo (>200 caracteres), pode ser truncado no PDF')
    }
  }

  // Validar tipo de escopo
  if (!data.tipo_escopo || typeof data.tipo_escopo !== 'string' || data.tipo_escopo.trim().length === 0) {
    errors.push({ field: 'tipo_escopo', message: 'Tipo de escopo é obrigatório' })
  }

  // Validar seções
  if (!data.sections || !Array.isArray(data.sections)) {
    warnings.push('Nenhuma seção fornecida, PDF conterá apenas informações básicas')
  } else {
    data.sections.forEach((section: any, index: number) => {
      if (!section.title || typeof section.title !== 'string' || section.title.trim().length === 0) {
        errors.push({ field: `sections[${index}].title`, message: `Título da seção ${index + 1} é obrigatório` })
      }
      if (!section.content || typeof section.content !== 'string') {
        warnings.push(`Seção "${section.title || index + 1}" sem conteúdo`)
      } else if (section.content.length > 10000) {
        warnings.push(`Seção "${section.title}" muito longa (>10k caracteres), pode afetar performance`)
      }
    })

    if (data.sections.length > 50) {
      warnings.push('Muitas seções (>50), PDF pode ficar muito extenso')
    }
  }

  // Validar customização (se fornecida)
  if (data.customization) {
    if (data.customization.header?.logoSize) {
      const { width, height } = data.customization.header.logoSize
      if (width <= 0 || height <= 0 || width > 100 || height > 100) {
        warnings.push('Tamanho do logo do header fora do recomendado (0-100mm)')
      }
    }

    if (data.customization.header?.customText && data.customization.header.customText.length > 100) {
      warnings.push('Texto customizado do header muito longo (>100 caracteres)')
    }

    if (data.customization.footer?.customText && data.customization.footer.customText.length > 150) {
      warnings.push('Texto customizado do footer muito longo (>150 caracteres)')
    }
  }

  // Validação de integridade geral
  const totalContentLength = (data.sections || []).reduce((total: number, section: any) => {
    return total + (section.content?.length || 0)
  }, 0)

  if (totalContentLength > 100000) {
    warnings.push('Conteúdo total muito extenso (>100k caracteres), geração pode ser lenta')
  }

  return {
    valid: errors.length === 0,
    errors,
    warnings
  }
}

