// Interface para configuração de header/footer customizáveis
interface PDFCustomization {
  header?: {
    showLogo?: boolean
    showDate?: boolean
    customText?: string
    logoSize?: { width: number; height: number }
  }
  footer?: {
    showLogo?: boolean
    showPageNumber?: boolean
    customText?: string
    companyInfo?: {
      name?: string
      cnpj?: string
      website?: string
      email?: string
      phone?: string
    }
  }
}

// Interface para validação de dados
interface ValidationError {
  field: string
  message: string
}

interface ValidationResult {
  valid: boolean
  errors: ValidationError[]
  warnings: string[]
}

// Interface para os dados da proposta
interface WaProjectProposalData {
  projeto: {
    nome: string
  }
  data_emissao: string
  validade_dias: string
  cliente: {
    nome: string
  }
  tipo_escopo: string
  sections: ProposalSection[]
  numeracao_pagina: string
  customization?: PDFCustomization
}

// Classe principal para geração de PDF
export class WaProjectPDFGenerator {
  private doc: jsPDF
  private currentY: number
  private pageNumber: number
  private sectionCount: number = 0
  private estimatedHeight: number = 0
  private customization: PDFCustomization

  // Configurações de página (A4) seguindo o PDF oficial
  private readonly pageWidth = 210
  private readonly pageHeight = 297
  private readonly margin = {
    top: 25, // Margem superior conforme PDF
    right: 25, // Margem direita conforme PDF
    bottom: 25, // Margem inferior conforme PDF
    left: 25, // Margem esquerda conforme PDF
  }

  // Cache para otimização de medidas de texto
  private textWidthCache: Map<string, number> = new Map()

  constructor(customization: PDFCustomization = {}) {
    this.doc = new jsPDF({
      orientation: 'portrait',
      unit: 'mm',
      format: 'a4',
      compress: true, // Ativar compressão para PDFs grandes
      putOnlyUsedFonts: true, // Incluir apenas fontes utilizadas
      precision: 2 // Precisão de coordenadas para otimização
    })
    this.currentY = this.margin.top
    this.pageNumber = 1
    this.customization = {
      header: {
        showLogo: true,
        showDate: true,
        logoSize: { width: 25, height: 22 },
        ...customization.header
      },
      footer: {
        showLogo: true,
        showPageNumber: true,
        companyInfo: {
          name: 'Wa Project Soluções Tecnológicas LTDA.',
          cnpj: '19.317.018/0001-40',
          website: 'waproject.com.br',
          email: 'comercial@waproject.com.br',
          phone: '(11) 5028-2010'
        },
        ...customization.footer
      }
    }

    // Configurar fonte e codificação
    this.setupFonts()
  }

  private setupFonts() {
    // Configurar fonte padrão com suporte a UTF-8
    this.doc.setFont('helvetica')

    // Definir propriedades de documento para UTF-8
    this.doc.setProperties({
      title: 'Proposta Comercial Wa Project',
      creator: 'Wa Project PDF Generator',
      author: 'Wa Project',
      keywords: 'proposta, comercial, wa project',
      subject: 'Proposta Comercial'
    })

    // Configurar codificação de texto para caracteres especiais
    this.doc.setCharSpace(0)
    this.doc.setWordSpace(0)
  }

  // Função para limpar e normalizar texto para o PDF
  private sanitizeText(text: string): string {
    if (!text || typeof text !== 'string') {
      return ''
    }

    // Primeiro tentar corrigir problemas de codificação
    const fixedText = this.fixEncoding(text)

    return fixedText
      // Normalizar quebras de linha
      .replace(/\r\n/g, '\n')
      .replace(/\r/g, '\n')
      // Substituir caracteres especiais problemáticos
      .replace(/[""]/g, '"')
      .replace(/['']/g, "'")
      .replace(/[–—]/g, '-')
      .replace(/…/g, '...')
      // Como fallback, remover acentos se ainda houver problemas
      .replace(/[àáâãä]/g, 'a')
      .replace(/[èéêë]/g, 'e')
      .replace(/[ìíîï]/g, 'i')
      .replace(/[òóôõö]/g, 'o')
      .replace(/[ùúûü]/g, 'u')
      .replace(/[ç]/g, 'c')
      .replace(/[ñ]/g, 'n')
      // Versões maiúsculas
      .replace(/[ÀÁÂÃÄ]/g, 'A')
      .replace(/[ÈÉÊË]/g, 'E')
      .replace(/[ÌÍÎÏ]/g, 'I')
      .replace(/[ÒÓÔÕÖ]/g, 'O')
      .replace(/[ÙÚÛÜ]/g, 'U')
      .replace(/[Ç]/g, 'C')
      .replace(/[Ñ]/g, 'N')
      // Remover caracteres de controle, mas manter quebras de linha
      .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
      // Normalizar espaços múltiplos
      .replace(/ +/g, ' ')
      .trim()
  }

  // Função para detectar problemas de codificação e tentar corrigi-los
  private fixEncoding(text: string): string {
    if (!text) return text

    // Detectar e corrigir alguns problemas comuns de codificação UTF-8
    return text
      // Corrigir sequências mal codificadas comuns
      .replace(/Ã¡/g, 'á')
      .replace(/Ã /g, 'à')
      .replace(/Ã¢/g, 'â')
      .replace(/Ã£/g, 'ã')
      .replace(/Ã©/g, 'é')
      .replace(/Ãª/g, 'ê')
      .replace(/Ã­/g, 'í')
      .replace(/Ã³/g, 'ó')
      .replace(/Ã´/g, 'ô')
      .replace(/Ãµ/g, 'õ')
      .replace(/Ãº/g, 'ú')
      .replace(/Ã§/g, 'ç')
      // Versões maiúsculas
      .replace(/Ã\x81/g, 'Á')
      .replace(/Ã\x80/g, 'À')
      .replace(/Ã\x82/g, 'Â')
      .replace(/Ã\x83/g, 'Ã')
      .replace(/Ã\x89/g, 'É')
      .replace(/Ã\x8A/g, 'Ê')
      .replace(/Ã\x8D/g, 'Í')
      .replace(/Ã\x93/g, 'Ó')
      .replace(/Ã\x94/g, 'Ô')
      .replace(/Ã\x95/g, 'Õ')
      .replace(/Ã\x9A/g, 'Ú')
      .replace(/Ã\x87/g, 'Ç')
  }

  // Versão melhorada de splitTextToSize com tratamento de caracteres especiais
  private splitTextSafe(text: string, maxWidth: number): string[] {
    const sanitized = this.sanitizeText(text)
    return this.doc.splitTextToSize(sanitized, maxWidth)
  }

  // Versão melhorada de text() com sanitização automática
  private addTextSafe(
    text: string,
    x: number,
    y: number,
    options?: {
      align?: 'left' | 'center' | 'right'
      angle?: number
      maxWidth?: number
    }
  ): void {
    const sanitized = this.sanitizeText(text)

    if (options?.maxWidth) {
      const lines = this.splitTextSafe(sanitized, options.maxWidth)
      lines.forEach((line, index) => {
        const lineY = y + (index * 6)
        this.doc.text(line, x, lineY, {
          align: options.align,
          angle: options.angle
        })
      })
    } else {
      this.doc.text(sanitized, x, y, {
        align: options?.align,
        angle: options?.angle
      })
    }
  }

  private get contentWidth() {
    return this.pageWidth - this.margin.left - this.margin.right
  }

  private get contentStartX() {
    return this.margin.left
  }

  // Método otimizado para obter largura de texto com cache
  private getTextWidthCached(text: string): number {
    const key = `${text}_${this.doc.getFontSize()}_${this.doc.getFont().fontName}_${this.doc.getFont().fontStyle}`

    if (this.textWidthCache.has(key)) {
      return this.textWidthCache.get(key)!
    }

    const width = this.doc.getTextWidth(text)
    this.textWidthCache.set(key, width)
    return width
  }

  // Estimar altura total da proposta (para otimizar alocação de páginas)
  private estimateTotalHeight(data: WaProjectProposalData): number {
    let estimated = 100 // Capa base

    // Estimativa baseada no número de seções e conteúdo
    if (data.sections && data.sections.length > 0) {
      data.sections.forEach(section => {
        estimated += 15 // Título da seção
        estimated += section.content.split('\n').length * 6 // Aproximação do conteúdo
        estimated += 10 // Espaçamento entre seções
      })
    }

    estimated += 60 // Páginas finais fixas (próximos passos, encerramento)

    return estimated
  }

  // Otimização para renderização em lote
  private batchRenderItems<T>(
    items: T[],
    renderFn: (item: T, index: number) => void,
    batchSize: number = 10
  ): void {
    for (let i = 0; i < items.length; i += batchSize) {
      const batch = items.slice(i, i + batchSize)
      batch.forEach((item, index) => renderFn(item, i + index))

      // Yield para não bloquear a UI em listas muito grandes
      if (i + batchSize < items.length && items.length > 50) {
        setTimeout(() => {}, 0)
      }
    }
  }

  private addWatermark() {
    // Marca d'água do logo Wa Project no centro da página
    const watermarkX = this.pageWidth / 2 - 30
    const watermarkY = this.pageHeight / 2 - 30

    try {
      this.doc.addImage(
        WA_PROJECT_LOGO_BASE64,
        'SVG',
        watermarkX,
        watermarkY,
        60, // largura da marca d'água
        52, // altura da marca d'água
        undefined,
        'FAST'
      )

      // Definir opacidade baixa para marca d'água
      this.doc.setGState(this.doc.GState({opacity: 0.05}))

      // Voltar opacidade normal
      this.doc.setGState(this.doc.GState({opacity: 1.0}))
    } catch (error) {
      // Fallback: marca d'água textual
      this.doc.setTextColor('#E8E8E8')
      this.doc.setFontSize(48)
      this.doc.setFont('helvetica', 'bold')
      this.doc.text('Wa Project', watermarkX, watermarkY, {
        angle: 45,
        align: 'center'
      })
    }
  }

  private addHeader(data?: WaProjectProposalData) {
    if (!this.customization.header?.showLogo && !this.customization.header?.customText) {
      return
    }

    const headerStartY = this.currentY

    // Logo customizável
    if (this.customization.header?.showLogo) {
      try {
        const logoSize = this.customization.header.logoSize || { width: 25, height: 22 }
        this.doc.addImage(
          WA_PROJECT_LOGO_BASE64,
          'SVG',
          this.contentStartX,
          headerStartY,
          logoSize.width,
          logoSize.height,
          undefined,
          'FAST'
        )
      } catch (error) {
        // Fallback: logo textual
        this.doc.setFillColor(WA_COLORS.primary)
        this.doc.roundedRect(this.contentStartX, headerStartY, 25, 10, 2, 2, 'F')

        this.doc.setTextColor('#ffffff')
        this.doc.setFontSize(10)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text('Wa Project', this.contentStartX + 3, headerStartY + 7)
      }
    }

    // Texto customizado no header
    if (this.customization.header?.customText) {
      this.doc.setTextColor(WA_COLORS.primary)
      this.doc.setFontSize(10)
      this.doc.setFont('helvetica', 'normal')
      const textWidth = this.getTextWidthCached(this.customization.header.customText)
      const textX = this.pageWidth - this.margin.right - textWidth
      this.doc.text(this.customization.header.customText, textX, headerStartY + 15)
    }

    // Data no header (se configurado)
    if (this.customization.header?.showDate && data) {
      this.doc.setTextColor(WA_COLORS.textMuted)
      this.doc.setFontSize(9)
      this.doc.setFont('helvetica', 'normal')
      const dateText = `Data: ${data.data_emissao}`
      const textWidth = this.getTextWidthCached(dateText)
      const textX = this.pageWidth - this.margin.right - textWidth
      this.doc.text(dateText, textX, headerStartY + 6)
    }

    this.currentY = headerStartY + 30
  }

  // Manter compatibilidade com método original
  private addLogo() {
    this.addHeader()
  }

  private addTitle(title: string, subtitle?: string) {
    // Título principal conforme PDF
    this.doc.setTextColor(WA_COLORS.primary)
    this.doc.setFontSize(28)
    this.doc.setFont('helvetica', 'bold')

    this.addTextSafe(title, this.contentStartX, this.currentY)
    this.currentY += 15

    // Subtítulo do projeto conforme PDF
    if (subtitle) {
      this.doc.setFontSize(22)
      this.doc.setFont('helvetica', 'bold')
      this.doc.setTextColor(WA_COLORS.primary)
      this.addTextSafe(subtitle, this.contentStartX, this.currentY)
      this.currentY += 12
    }

    this.currentY += 8
  }

  private addCoverInfo(data: WaProjectProposalData) {
    // Centralizar informações
    this.doc.setTextColor(WA_COLORS.text)
    this.doc.setFontSize(11)
    this.doc.setFont('helvetica', 'normal')

    const infoLines = [
      `${data.data_emissao} | Válido por ${data.validade_dias} dias`,
      `Para: ${data.cliente.nome}`,
      `Tipo: ${data.tipo_escopo}`
    ]

    infoLines.forEach(line => {
      const lineWidth = this.getTextWidthCached(line)
      const centerX = (this.pageWidth - lineWidth) / 2
      this.doc.text(line, centerX, this.currentY)
      this.currentY += 6
    })

    this.currentY += 15
  }

  private checkPageBreak(neededHeight: number, context: 'title' | 'paragraph' | 'list' | 'section' = 'paragraph'): boolean {
    const availableSpace = this.pageHeight - this.margin.bottom - 15 - this.currentY

    // Se não cabe de forma alguma, quebra a página
    if (neededHeight > availableSpace) {
      this.addPageNumber()
      this.newPage()
      return true
    }

    // Lógica inteligente baseada no contexto
    switch (context) {
      case 'title':
        // Títulos precisam de pelo menos 20mm de espaço após eles para evitar órfãos
        if (availableSpace < neededHeight + 20) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break

      case 'section':
        // Seções precisam de pelo menos 30mm de espaço para não quebrar no início
        if (availableSpace < neededHeight + 30) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break

      case 'list':
        // Listas pequenas (até 3 itens) não devem quebrar
        if (neededHeight <= 25 && availableSpace < neededHeight) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break

      case 'paragraph':
      default:
        // Parágrafos pequenos (até 15mm) não devem quebrar
        if (neededHeight <= 15 && availableSpace < neededHeight) {
          this.addPageNumber()
          this.newPage()
          return true
        }
        break
    }

    return false
  }

  private newPage() {
    this.doc.addPage()
    this.pageNumber++
    this.currentY = this.margin.top + 5
    this.addWatermark()
    this.addFooterLogo()
  }

  private addCustomFooter() {
    const footerY = this.pageHeight - 15

    // Logo customizável no rodapé
    if (this.customization.footer?.showLogo) {
      try {
        this.doc.addImage(
          WA_PROJECT_LOGO_BASE64,
          'SVG',
          this.contentStartX,
          footerY - 10,
          20,
          8,
          undefined,
          'FAST'
        )
      } catch (error) {
        // Fallback textual
        this.doc.setTextColor(WA_COLORS.primary)
        this.doc.setFontSize(8)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text('Wa Project', this.contentStartX, footerY)
      }
    }

    // Texto customizado no rodapé (centro)
    if (this.customization.footer?.customText) {
      this.doc.setTextColor(WA_COLORS.textMuted)
      this.doc.setFontSize(8)
      this.doc.setFont('helvetica', 'normal')
      const textWidth = this.getTextWidthCached(this.customization.footer.customText)
      const centerX = (this.pageWidth - textWidth) / 2
      this.doc.text(this.customization.footer.customText, centerX, footerY)
    }

    // Número da página customizável (direita)
    if (this.customization.footer?.showPageNumber) {
      this.doc.setTextColor(WA_COLORS.primary)
      this.doc.setFontSize(10)
      this.doc.setFont('helvetica', 'normal')
      this.doc.text(
        this.pageNumber.toString(),
        this.pageWidth - this.margin.right,
        footerY,
        { align: 'right' }
      )
    }
  }

  // Manter compatibilidade com método original
  private addFooterLogo() {
    this.addCustomFooter()
  }

  private addPageNumber() {
    this.doc.setFontSize(9)
    this.doc.setTextColor(WA_COLORS.textMuted)
    this.doc.text(
      this.pageNumber.toString(),
      this.pageWidth / 2,
      this.pageHeight - 10,
      { align: 'center' }
    )
  }

  private addSectionTitle(title: string) {
    this.checkPageBreak(15, 'title')

    this.doc.setTextColor(WA_COLORS.primary)
    this.doc.setFontSize(16)
    this.doc.setFont('helvetica', 'bold')
    this.doc.text(title, this.contentStartX, this.currentY)
    this.currentY += 12
  }

  private addParagraph(text: string) {
    this.doc.setTextColor(WA_COLORS.text)
    this.doc.setFontSize(11)
    this.doc.setFont('helvetica', 'normal')

    const lines = this.splitTextSafe(text, this.contentWidth)

    // Calcular altura total do parágrafo
    const totalParagraphHeight = lines.length * 6 + 4

    // Verificar se o parágrafo inteiro cabe na página
    this.checkPageBreak(totalParagraphHeight, 'paragraph')

    lines.forEach((line: string) => {
      this.addTextSafe(line, this.contentStartX, this.currentY)
      this.currentY += 6
    })

    this.currentY += 4
  }

  private addBulletList(items: string[]) {
    // Calcular altura estimada da lista completa
    const estimatedListHeight = items.length * 8
    this.checkPageBreak(estimatedListHeight, 'list')

    // Para listas grandes, usar renderização em lote
    if (items.length > 20) {
      this.batchRenderItems(items, (item, index) => {
        this.renderBulletItem(item)
      })
    } else {
      // Para listas pequenas, renderização direta
      items.forEach(item => {
        this.renderBulletItem(item)
      })
    }
  }

  private renderBulletItem(item: string) {
    // Para itens individuais, usar contexto de parágrafo
    this.checkPageBreak(8, 'paragraph')

    // Bullet point
    this.doc.setTextColor(WA_COLORS.primary)
    this.addTextSafe('•', this.contentStartX, this.currentY)

    // Texto do item
    this.doc.setTextColor(WA_COLORS.textMuted)
    this.doc.setFontSize(10)
    this.doc.setFont('helvetica', 'normal')

    const lines = this.splitTextSafe(item, this.contentWidth - 8)
    lines.forEach((line: string, lineIndex: number) => {
      if (lineIndex > 0) this.checkPageBreak(5, 'paragraph')
      this.addTextSafe(line, this.contentStartX + 6, this.currentY)
      if (lineIndex < lines.length - 1) this.currentY += 5
    })

    this.currentY += 6
  }

  private parseMarkdownContent(content: string): void {
    const lines = content.split('\n')

    for (const line of lines) {
      const trimmed = line.trim()

      if (!trimmed) {
        this.currentY += 3
        continue
      }

      // Títulos
      if (trimmed.startsWith('### ') || trimmed.startsWith('## ') || trimmed.startsWith('# ')) {
        const titleText = trimmed.replace(/^#+\s+/, '')

        // Verificar quebra de página para títulos
        this.checkPageBreak(8, 'title')

        this.doc.setTextColor(WA_COLORS.primary)
        this.doc.setFontSize(12)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text(titleText, this.contentStartX, this.currentY)
        this.currentY += 8
        continue
      }

      // Listas com bullets
      if (trimmed.startsWith('• ') || trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
        const itemText = trimmed.slice(2).replace(/\*\*(.*?)\*\*/g, '$1')
        this.addBulletList([itemText])
        continue
      }

      // Listas numeradas
      const numberedMatch = trimmed.match(/^(\d+)\.\s+(.+)$/)
      if (numberedMatch) {
        const itemText = numberedMatch[2].replace(/\*\*(.*?)\*\*/g, '$1')

        this.checkPageBreak(8, 'paragraph')
        this.doc.setTextColor(WA_COLORS.primary)
        this.doc.setFont('helvetica', 'bold')
        this.doc.text(`${numberedMatch[1]}.`, this.contentStartX, this.currentY)

        this.doc.setTextColor(WA_COLORS.textMuted)
        this.doc.setFont('helvetica', 'normal')
        this.doc.text(itemText, this.contentStartX + 8, this.currentY)
        this.currentY += 6
        continue
      }

      // Parágrafos regulares
      if (trimmed && !trimmed.startsWith('-') && !trimmed.startsWith('|')) {
        const plainText = trimmed.replace(/\*\*(.*?)\*\*/g, '$1')
        this.addParagraph(plainText)
      }
    }
  }

  public generate(data: WaProjectProposalData, progressCallback?: (progress: number) => void): void {
    // Estimar altura total para otimização
    this.estimatedHeight = this.estimateTotalHeight(data)

    // Adicionar marca d'água na primeira página
    this.addWatermark()
    progressCallback?.(5)

    // PÁGINA 1: CAPA
    this.addHeader(data)
    this.addTitle('Proposta Comercial', data.projeto.nome)
    this.addCoverInfo(data)
    progressCallback?.(15)

    // Seções de conteúdo
    if (data.sections && data.sections.length > 0) {
      // Sobre a Wa Project (primeira seção ou seção padrão)
      this.addSectionTitle('Sobre a Wa Project')
      this.addParagraph('A Wa Project é uma software house com mais de 13 anos de experiência no desenvolvimento de soluções tecnológicas customizadas.')

      // Nossos serviços
      this.addParagraph('Nossos serviços:')
      this.addBulletList([
        'Desenvolvimento de Software.',
        'Desenvolvimento de Aplicativos.',
        'Soluções de Inteligência Artificial.',
        'Alocação de Profissionais.'
      ])

      // Nossos Clientes
      this.addSectionTitle('Nossos Clientes')
      this.addBulletList([
        'PepsiCo',
        'Vtex',
        'Santillana',
        'Dasa',
        'WideLabs',
        'Confederação Brasileira de Hipismo',
        'Forbes',
        'Easy Salon',
        'InstaCarro',
        'Antilhas',
        'Fundação Carlos Chagas',
        'Funarbe'
      ])
      this.addParagraph('Cases completos: waproject.com.br/cases')

      // Nova página para conteúdo específico do projeto
      this.newPage()
      progressCallback?.(40)

      // Processar seções da proposta com progresso
      const totalSections = data.sections.length
      data.sections.forEach((section, index) => {
        // Verificar se há espaço suficiente para iniciar uma seção
        this.checkPageBreak(25, 'section')

        this.addSectionTitle(section.title)
        this.parseMarkdownContent(section.content)
        this.currentY += 5
        this.sectionCount++

        // Atualizar progresso (40% a 80% para seções)
        const sectionProgress = 40 + (index / totalSections) * 40
        progressCallback?.(Math.round(sectionProgress))
      })
    }

    // PÁGINA FINAL: Fechamento
    this.newPage()
    progressCallback?.(80)

    // Próximos Passos
    this.addSectionTitle('Próximos Passos')
    this.addBulletList([
      'Aprovação desta proposta comercial',
      'Assinatura do contrato de prestação de serviços',
      'Kick-off do projeto',
      'Início do desenvolvimento'
    ])

    this.addParagraph('Estamos à disposição para esclarecer dúvidas e ansiosos para iniciar esta parceria!')
    progressCallback?.(90)

    // Encerramento
    this.currentY += 15

    // Citação
    this.doc.setTextColor(WA_COLORS.primary)
    this.doc.setFontSize(14)
    this.doc.setFont('helvetica', 'bold')
    const quote = 'Não é sobre desenvolvimento, é sobre envolvimento.'
    const quoteWidth = this.getTextWidthCached(quote)
    const quoteCenterX = (this.pageWidth - quoteWidth) / 2
    this.doc.text(quote, quoteCenterX, this.currentY)
    this.currentY += 10

    this.doc.setFontSize(12)
    const thanks = 'Obrigado por confiar na Wa Project!'
    const thanksWidth = this.getTextWidthCached(thanks)
    const thanksCenterX = (this.pageWidth - thanksWidth) / 2
    this.doc.text(thanks, thanksCenterX, this.currentY)
    this.currentY += 15

    // Informações da empresa customizáveis
    this.addCompanyInfo()

    this.currentY += 10

    // Validade
    this.doc.setTextColor(WA_COLORS.textMuted)
    this.doc.setFontSize(9)
    const validity = `Proposta válida por ${data.validade_dias} dias a partir da data de emissão`
    const validityWidth = this.doc.getTextWidth(validity)
    const validityCenterX = (this.pageWidth - validityWidth) / 2
    this.doc.text(validity, validityCenterX, this.currentY)

    // Adicionar rodapé na página final
    this.addFooterLogo()
  }

  private addCompanyInfo() {
    const companyInfo = this.customization.footer?.companyInfo

    if (!companyInfo) return

    // Nome da empresa
    if (companyInfo.name) {
      this.doc.setTextColor(WA_COLORS.text)
      this.doc.setFontSize(10)
      this.doc.setFont('helvetica', 'bold')
      const companyWidth = this.getTextWidthCached(companyInfo.name)
      const companyCenterX = (this.pageWidth - companyWidth) / 2
      this.doc.text(companyInfo.name, companyCenterX, this.currentY)
      this.currentY += 6
    }

    // Informações de contato
    this.doc.setFont('helvetica', 'normal')
    const infoLines = []

    if (companyInfo.cnpj) infoLines.push(`CNPJ: ${companyInfo.cnpj}`)
    if (companyInfo.website) infoLines.push(`Website: ${companyInfo.website}`)
    if (companyInfo.email) infoLines.push(`Email: ${companyInfo.email}`)
    if (companyInfo.phone) infoLines.push(`Telefone/WhatsApp: ${companyInfo.phone}`)

    infoLines.forEach(line => {
      const lineWidth = this.getTextWidthCached(line)
      const lineCenterX = (this.pageWidth - lineWidth) / 2
      this.doc.text(line, lineCenterX, this.currentY)
      this.currentY += 5
    })
  }

  public save(filename: string): void {
    this.doc.save(filename)
  }
}

// Função principal para gerar o PDF da proposta Wa Project
export function generateWaProjectProposalPDF(
  data: WaProjectProposalData,
  options?: {
    progressCallback?: (progress: number) => void
    filename?: string
    customization?: PDFCustomization
    skipValidation?: boolean
    onValidationWarnings?: (warnings: string[]) => void
  }
): Promise<void> {
  return new Promise((resolve, reject) => {
    try {
      // Validar dados antes de gerar (opcional)
      if (!options?.skipValidation) {
        const validation = validateProposalData(data)

        if (!validation.valid) {
          const errorMessage = `Validação falhou: ${validation.errors.map(e => `${e.field}: ${e.message}`).join(', ')}`
          reject(new Error(errorMessage))
          return
        }

        // Reportar warnings se callback fornecido
        if (validation.warnings.length > 0 && options?.onValidationWarnings) {
          options.onValidationWarnings(validation.warnings)
        }
      }

      // Usar customização da opções ou dos dados da proposta
      const customization = options?.customization || data.customization || {}
      const generator = new WaProjectPDFGenerator(customization)

      // Usar setTimeout para tornar a geração assíncrona e não bloquear a UI
      setTimeout(() => {
        try {
          generator.generate(data, options?.progressCallback)
          options?.progressCallback?.(95)

          // Sanitizar nome do arquivo
          const sanitizedProjectName = data.projeto.nome
            .replace(/[^a-zA-Z0-9\-_\s]/g, '') // Remove caracteres especiais
            .replace(/\s+/g, '_') // Substitui espaços por underscore
            .substring(0, 50) // Limita tamanho

          const sanitizedDate = data.data_emissao.replace(/\//g, '-')

          const filename = options?.filename ||
            `Proposta_${sanitizedProjectName}_${sanitizedDate}.pdf`

          generator.save(filename)
          options?.progressCallback?.(100)

          resolve()
        } catch (error) {
          console.error('Erro ao gerar PDF da Wa Project:', error)
          reject(error)
        }
      }, 10) // Pequeno delay para permitir que a UI atualize
    } catch (error) {
      console.error('Erro ao inicializar geração de PDF da Wa Project:', error)
      reject(error)
    }
  })
}

"use client"

import React, { useState, useRef, useCallback } from 'react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Skeleton } from '@/components/ui/skeleton'
import { Progress } from '@/components/ui/progress'
import { Download, Eye, FileText, AlertCircle, CheckCircle, Loader2 } from 'lucide-react'
import { toast } from 'sonner'
import { ProposalTemplateRenderer } from './ProposalTemplateRenderer'
import { gerarPDFProposta, validarDadosParaPDF, criarPropostaExemplo } from '@/lib/proposta-pdf-generator'
import type { PropostaTemplateData } from '@/lib/proposta-template-types'

interface ProposalTemplateManagerProps {
  data?: PropostaTemplateData
  onDataChange?: (data: PropostaTemplateData) => void
  className?: string
  showControls?: boolean // controla se mostra botões de ação
  previewMode?: 'full' | 'compact' // modo de preview
}

interface ValidationResult {
  valido: boolean
  erros: string[]
}

export function ProposalTemplateManager({
  data: initialData,
  onDataChange,
  className,
  showControls = true,
  previewMode = 'full'
}: ProposalTemplateManagerProps) {
  const [data, setData] = useState<PropostaTemplateData>(
    initialData || criarPropostaExemplo()
  )
  const [isLoading, setIsLoading] = useState(!initialData) // Se não há dados iniciais, está carregando
  const [isGeneratingPDF, setIsGeneratingPDF] = useState(false)
  const [pdfProgress, setPdfProgress] = useState(0)
  const [progressStatus, setProgressStatus] = useState<string>('')
  const [validation, setValidation] = useState<ValidationResult | null>(null)
  const previewRef = useRef<HTMLDivElement>(null)

  // Controlar loading quando dados externos mudam
  React.useEffect(() => {
    if (initialData && initialData !== data) {
      setIsLoading(true)
      // Simular um pequeno delay para mostrar skeleton
      const timer = setTimeout(() => {
        setData(initialData)
        setIsLoading(false)
        onDataChange?.(initialData)
      }, 500)
      return () => clearTimeout(timer)
    }
  }, [initialData, data, onDataChange])

  // Atualiza dados e notifica parent component
  const handleDataChange = (newData: PropostaTemplateData) => {
    setData(newData)
    onDataChange?.(newData)
    // Revalidar quando dados mudam
    if (validation) {
      setValidation(validarDadosParaPDF(newData))
    }
  }

  // Validar dados para PDF
  const handleValidate = useCallback(() => {
    const result = validarDadosParaPDF(data)
    setValidation(result)

    if (result.valido) {
      toast.success("Dados válidos para geração de PDF!")
    } else {
      toast.error(`Encontrados ${result.erros.length} erro(s) de validação`)
    }

    return result.valido
  }, [data, validation])

  // Callback de progresso para PDF
  const handleProgressUpdate = useCallback((progress: number) => {
    setPdfProgress(progress)

    // Atualizar status baseado no progresso
    if (progress <= 5) {
      setProgressStatus('Inicializando geração...')
    } else if (progress <= 15) {
      setProgressStatus('Criando capa...')
    } else if (progress <= 40) {
      setProgressStatus('Adicionando informações da empresa...')
    } else if (progress <= 80) {
      setProgressStatus('Processando seções do projeto...')
    } else if (progress <= 90) {
      setProgressStatus('Finalizando próximos passos...')
    } else if (progress <= 95) {
      setProgressStatus('Salvando arquivo PDF...')
    } else {
      setProgressStatus('Concluído!')
    }
  }, [])

  // Gerar PDF
  const handleGeneratePDF = useCallback(async () => {
    try {
      // Validar dados primeiro
      const validationResult = validarDadosParaPDF(data)
      if (!validationResult.valido) {
        setValidation(validationResult)
        toast.error("Dados inválidos. Corrija os erros antes de gerar o PDF.")
        return
      }

      setIsGeneratingPDF(true)
      setPdfProgress(0)
      setProgressStatus('Preparando...')

      // Gerar PDF com callback de progresso
      await gerarPDFProposta(data, {
        download: true,
        filename: `proposta_${data.capa.cliente.empresa.replace(/\s+/g, '_').toLowerCase()}_${new Date().toISOString().slice(0, 10)}`,
        progressCallback: handleProgressUpdate
      })

      toast.success("PDF gerado e baixado com sucesso!")
    } catch (error) {
      toast.error("Erro ao gerar PDF. Verifique os dados e tente novamente.")
      console.error('Erro na geração do PDF:', error)
    } finally {
      setIsGeneratingPDF(false)
      setPdfProgress(0)
      setProgressStatus('')
    }
  }, [data, handleProgressUpdate])

  // Scroll para seção específica do preview
  const scrollToSection = useCallback((sectionId: string) => {
    if (previewRef.current) {
      const section = previewRef.current.querySelector(`[data-section="${sectionId}"]`)
      if (section) {
        section.scrollIntoView({ behavior: 'smooth', block: 'start' })
      }
    }
  }, [])

  // Renderizar preview compacto
  if (previewMode === 'compact') {
    return (
      <div className={className}>
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5" />
              Preview da Proposta
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {/* Info resumida */}
              {isLoading ? (
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <Skeleton className="h-4 w-16" />
                    <Skeleton className="h-3 w-24" />
                  </div>
                  <div className="space-y-1">
                    <Skeleton className="h-4 w-16" />
                    <Skeleton className="h-3 w-32" />
                  </div>
                  <div className="space-y-1">
                    <Skeleton className="h-4 w-12" />
                    <Skeleton className="h-3 w-20" />
                  </div>
                  <div className="space-y-1">
                    <Skeleton className="h-4 w-12" />
                    <Skeleton className="h-3 w-16" />
                  </div>
                </div>
              ) : (
                <div className="grid grid-cols-2 gap-4 text-sm">
                  <div>
                    <strong>Cliente:</strong> {data.capa.cliente.empresa}
                  </div>
                  <div>
                    <strong>Projeto:</strong> {data.projeto.nome}
                  </div>
                  <div>
                    <strong>Valor:</strong> {data.investimento.valorTotal}
                  </div>
                  <div>
                    <strong>Prazo:</strong> {data.cronograma.prazoTotal}
                  </div>
                </div>
              )}

              {/* Progress Bar */}
              {isGeneratingPDF && (
                <div className="space-y-2">
                  <Progress value={pdfProgress} className="h-2" />
                  <div className="flex items-center justify-between text-xs text-muted-foreground">
                    <span>{progressStatus}</span>
                    <span>{pdfProgress}%</span>
                  </div>
                </div>
              )}

              {/* Controles */}
              {showControls && (
                <div className="flex items-center gap-2 pt-4 border-t">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handleValidate}
                    disabled={isGeneratingPDF}
                  >
                    <CheckCircle className="h-4 w-4 mr-1" />
                    Validar
                  </Button>
                  <Button
                    size="sm"
                    onClick={handleGeneratePDF}
                    disabled={isGeneratingPDF}
                    className="bg-primary text-primary-foreground hover:bg-primary/90"
                  >
                    {isGeneratingPDF ? (
                      <div className="flex items-center">
                        <Loader2 className="h-4 w-4 animate-spin mr-1" />
                        Gerando...
                      </div>
                    ) : (
                      <>
                        <Download className="h-4 w-4 mr-1" />
                        Gerar PDF
                      </>
                    )}
                  </Button>
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    )
  }

  // Renderizar preview completo
  return (
    <div className={className}>
      <div className="grid grid-cols-1 xl:grid-cols-4 gap-6">
        {/* CONTROLES LATERAIS */}
        {showControls && (
          <div className="xl:col-span-1 space-y-4">
            {/* Controles de Ação */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Controles</CardTitle>
              </CardHeader>
              <CardContent className="space-y-3">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleValidate}
                  disabled={isGeneratingPDF}
                  className="w-full justify-start"
                >
                  <CheckCircle className="h-4 w-4 mr-2" />
                  Validar Dados
                </Button>

                <Button
                  size="sm"
                  onClick={handleGeneratePDF}
                  disabled={isGeneratingPDF}
                  className="w-full justify-start bg-primary text-primary-foreground hover:bg-primary/90"
                >
                  {isGeneratingPDF ? (
                    <div className="flex items-center">
                      <Loader2 className="h-4 w-4 animate-spin mr-2" />
                      Gerando PDF...
                    </div>
                  ) : (
                    <>
                      <Download className="h-4 w-4 mr-2" />
                      Gerar PDF
                    </>
                  )}
                </Button>

                {/* Progress Bar para modo full */}
                {isGeneratingPDF && (
                  <div className="space-y-2 pt-2">
                    <Progress value={pdfProgress} className="h-2" />
                    <div className="text-xs text-muted-foreground">
                      <div>{progressStatus}</div>
                      <div className="text-right">{pdfProgress}%</div>
                    </div>
                  </div>
                )}
              </CardContent>
            </Card>

            {/* Status de Validação */}
            {validation && (
              <Card>
                <CardHeader>
                  <CardTitle className="text-base flex items-center gap-2">
                    {validation.valido ? (
                      <CheckCircle className="h-4 w-4 text-green-600" />
                    ) : (
                      <AlertCircle className="h-4 w-4 text-red-600" />
                    )}
                    Validação
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  {validation.valido ? (
                    <p className="text-sm text-green-600">
                      ✓ Todos os dados estão válidos para geração de PDF
                    </p>
                  ) : (
                    <div className="space-y-2">
                      <p className="text-sm text-red-600 font-medium">
                        {validation.erros.length} erro(s) encontrado(s):
                      </p>
                      <ul className="text-sm text-red-600 space-y-1">
                        {validation.erros.map((erro, index) => (
                          <li key={index} className="flex items-start gap-1">
                            <span>•</span>
                            <span>{erro}</span>
                          </li>
                        ))}
                      </ul>
                    </div>
                  )}
                </CardContent>
              </Card>
            )}

            {/* Navegação por Seções */}
            <Card>
              <CardHeader>
                <CardTitle className="text-base">Navegação</CardTitle>
              </CardHeader>
              <CardContent>
                <nav className="space-y-1">
                  {[
                    { id: 'capa', label: 'Capa' },
                    { id: 'empresa', label: 'Sobre a Empresa' },
                    { id: 'projeto', label: 'Projeto' },
                    { id: 'funcionalidades', label: 'Funcionalidades' },
                    { id: 'cronograma', label: 'Cronograma' },
                    { id: 'investimento', label: 'Investimento' },
                    { id: 'encerramento', label: 'Encerramento' }
                  ].map((section) => (
                    <button
                      key={section.id}
                      onClick={() => scrollToSection(section.id)}
                      className="w-full text-left text-sm text-muted-foreground hover:text-foreground px-2 py-1 rounded hover:bg-muted/50 transition-colors"
                    >
                      {section.label}
                    </button>
                  ))}
                </nav>
              </CardContent>
            </Card>
          </div>
        )}

        {/* PREVIEW DA PROPOSTA */}
        <div className={`${showControls ? 'xl:col-span-3' : 'col-span-1'}`}>
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Eye className="h-5 w-5" />
                Preview da Proposta - {data.capa.cliente.empresa}
              </CardTitle>
            </CardHeader>
            <CardContent className="p-0">
              <div
                ref={previewRef}
                className="max-h-[800px] overflow-y-auto border rounded-lg bg-gray-50 p-4"
              >
                <ProposalTemplateRenderer data={data} isLoading={isLoading} />
              </div>
            </CardContent>
          </Card>
        </div>
      </div>
    </div>
  )
}

// === COMPONENTE DE LOADING ===
export function ProposalTemplateManagerSkeleton() {
  return (
    <div className="grid grid-cols-1 xl:grid-cols-4 gap-6">
      <div className="xl:col-span-1 space-y-4">
        <Card>
          <CardHeader>
            <Skeleton className="h-5 w-24" />
          </CardHeader>
          <CardContent className="space-y-3">
            <Skeleton className="h-8 w-full" />
            <Skeleton className="h-8 w-full" />
          </CardContent>
        </Card>
      </div>
      <div className="xl:col-span-3">
        <Card>
          <CardHeader>
            <Skeleton className="h-6 w-48" />
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              <Skeleton className="h-32 w-full" />
              <Skeleton className="h-24 w-full" />
              <Skeleton className="h-40 w-full" />
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  )
}

export default ProposalTemplateManager

