const http = require('http');
const fs = require('fs');
const path = require('path');

const port = 3001;
const htmlFile = path.join(__dirname, 'demo-template-proposta.html');

const server = http.createServer((req, res) => {
  if (req.url === '/' || req.url === '/demo-template-proposta.html') {
    try {
      const html = fs.readFileSync(htmlFile, 'utf8');
      res.writeHead(200, {
        'Content-Type': 'text/html; charset=utf-8',
        'Cache-Control': 'no-cache'
      });
      res.end(html);
    } catch (error) {
      res.writeHead(500, { 'Content-Type': 'text/plain' });
      res.end('Erro ao carregar o template: ' + error.message);
    }
  } else {
    res.writeHead(404, { 'Content-Type': 'text/plain' });
    res.end('Página não encontrada');
  }
});

server.listen(port, () => {
  console.log(`🚀 Servidor rodando em: http://localhost:${port}`);
  console.log(`📄 Template disponível em: http://localhost:${port}/demo-template-proposta.html`);
  console.log(`🖨️  Use Ctrl+P para testar impressão/PDF`);
  console.log(`⏹️  Pressione Ctrl+C para parar o servidor`);
});

server.on('error', (error) => {
  if (error.code === 'EADDRINUSE') {
    console.log(`❌ Porta ${port} já está em uso. Tentando porta ${port + 1}...`);
    server.listen(port + 1);
  } else {
    console.error('Erro no servidor:', error);
  }
});

