        box-sizing: border-box !important;
    }

    @page {
        size: A4;
        margin: 15mm 20mm 15mm 20mm;
    }

    html, body {
        width: 100% !important;
        height: 100% !important;
        background: white !important;
        font-size: 11pt !important;
        line-height: 1.4 !important;
        color: #1f2937 !important;
        -webkit-print-color-adjust: exact !important;
        print-color-adjust: exact !important;
    }

    .proposal-container {
        width: 100% !important;
        max-width: none !important;
        margin: 0 !important;
        padding: 0 !important;
        box-shadow: none !important;
        background: transparent !important;
    }

    .content {
        padding: 0 !important;
        margin: 0 !important;
        width: 100% !important;
    }

    /* Header otimizado */
    .header {
        margin-bottom: 15pt !important;
    }

    .logo {
        width: 80pt !important;
        height: 24pt !important;
        background: #003B71 !important;
        color: white !important;
        font-size: 10pt !important;
        margin-bottom: 15pt !important;
        border-radius: 2pt !important;
    }

    .main-title {
        font-size: 18pt !important;
        margin-bottom: 4pt !important;
        color: #003B71 !important;
    }

    .subtitle {
        font-size: 14pt !important;
        margin-bottom: 15pt !important;
        color: #003B71 !important;
    }

    .info-section {
        margin-bottom: 12pt !important;
        padding-top: 8pt !important;
        border-top: 0.5pt solid #e5e7eb !important;
    }

    .info-line {
        font-size: 10pt !important;
        margin-bottom: 2pt !important;
        color: #1f2937 !important;
    }

    /* Seções */
    .section {
        margin-bottom: 15pt !important;
        page-break-inside: avoid !important;
    }

    .section-title {
        font-size: 13pt !important;
        font-weight: bold !important;
        color: #003B71 !important;
        margin-bottom: 8pt !important;
        page-break-after: avoid !important;
    }

    .section-content {
        font-size: 10pt !important;
        color: #6b7280 !important;
        margin-bottom: 8pt !important;
        line-height: 1.4 !important;
    }

    /* Listas */
    .service-list, .client-list, .feature-list, .steps-list {
        margin-bottom: 8pt !important;
        padding-left: 12pt !important;
    }

    .service-list li, .client-list li, .feature-list li, .steps-list li {
        font-size: 10pt !important;
        margin-bottom: 2pt !important;
        color: #6b7280 !important;
    }

    .client-list {
        columns: 2 !important;
        column-gap: 15pt !important;
    }

    /* Funcionalidades e equipe */
    .functionality-item, .team-member {
        margin-bottom: 10pt !important;
        page-break-inside: avoid !important;
    }

    .functionality-title, .member-role {
        font-size: 10pt !important;
        font-weight: bold !important;
        color: #1f2937 !important;
        margin-bottom: 2pt !important;
    }

    .member-role {
        color: #003B71 !important;
    }

    .member-description {
        font-size: 9pt !important;
        color: #6b7280 !important;
    }

    /* Investimento */
    .investment-total {
        font-size: 12pt !important;
        font-weight: bold !important;
        color: #1f2937 !important;
        margin-bottom: 8pt !important;
    }

    .payment-condition {
        font-size: 10pt !important;
        margin-bottom: 2pt !important;
        color: #6b7280 !important;
    }

    .payment-condition strong {
        color: #1f2937 !important;
    }

    /* Encerramento */
    .closing {
        text-align: center !important;
        page-break-inside: avoid !important;
        margin-top: 20pt !important;
        padding-top: 15pt !important;
        border-top: 0.5pt solid #e5e7eb !important;
    }

    .quote {
        font-size: 12pt !important;
        font-weight: bold !important;
        color: #003B71 !important;
        margin-bottom: 8pt !important;
    }

    .company-info {
        margin: 12pt 0 !important;
    }

    .company-name {
        font-size: 10pt !important;
        font-weight: bold !important;
        color: #1f2937 !important;
        margin-bottom: 4pt !important;
    }

    .company-details {
        font-size: 9pt !important;
        color: #6b7280 !important;
        line-height: 1.3 !important;
    }

    .validity {
        font-size: 8pt !important;
        color: #6b7280 !important;
        margin-top: 8pt !important;
    }

    /* Watermark para impressão */
    .proposal-container::before {
        content: '';
        position: fixed !important;
        top: 50% !important;
        left: 50% !important;
        transform: translate(-50%, -50%) !important;
        width: 300pt !important;
        height: 300pt !important;
        background: url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 87"><polygon points="25,0 75,0 100,43.3 75,86.6 25,86.6 0,33.3" fill="%23003B71" opacity="0.03"/><text x="50" y="50" text-anchor="middle" fill="%23003B71" font-family="Arial,sans-serif" font-size="14" font-weight="bold" opacity="0.05">Wa</text></svg>') no-repeat center !important;
        background-size: contain !important;
        z-index: -1 !important;
        pointer-events: none !important;
    }

    /* Quebras de página estratégicas */
    .main-sections {
        page-break-before: always !important;
    }

    /* Ocultar elementos desnecessários na impressão */
    .no-print {
        display: none !important;
    }

    /* Forçar cores para impressão */
    .section-title, .main-title, .subtitle, .quote, .member-role {
        -webkit-print-color-adjust: exact !important;
        print-color-adjust: exact !important;
    }
}

